#include <iostream>
#include <exception>
using namespace std;

// Define custom exception class
class MyException : public exception {
public:
    const char* what() const noexcept override {
        return "Custom Exception: Something went wrong!";
    }
};

int main() {
    try {
        int age = -5;
        if (age < 0) {
            throw MyException();
        }
    }
    catch (const MyException& e) {
        cout << "Caught Exception: " << e.what() << endl;
    }

    return 0;
}

#include <iostream>
#include <exception>
#include <string>
using namespace std;

class InvalidInputException : public exception {
private:
    string message;
    int errorCode;
public:
    InvalidInputException(const string& msg, int code) : message(msg), errorCode(code) {}

    const char* what() const noexcept override {
        return message.c_str();
    }

    int getErrorCode() const {
        return errorCode;
    }
};

int divide(int a, int b) {
    if (b == 0) {
        throw InvalidInputException("Division by zero error!", 100);
    }
    if (a < 0 || b < 0) {
        throw InvalidInputException("Negative numbers not allowed!", 101);
    }
    return a / b;
}

int main() {
    try {
        int result = divide(10, -2);
        cout << "Result: " << result << endl;
    }
    catch (const InvalidInputException& e) {
        cout << "Error: " << e.what() << endl;
        cout << "Error Code: " << e.getErrorCode() << endl;
    }

    return 0;
}

#include <iostream>
#include <exception>
#include <string>
using namespace std;

// Custom exceptions for banking operations
class BankException : public exception {
protected:
    string msg;
public:
    BankException(const string& m) : msg(m) {}
    const char* what() const noexcept override { return msg.c_str(); }
};

class InsufficientFundsException : public BankException {
private:
    double balance;
    double withdrawalAmount;
public:
    InsufficientFundsException(double bal, double amt) 
        : BankException("Insufficient funds!"), balance(bal), withdrawalAmount(amt) {}
    double getBalance() const { return balance; }
    double getWithdrawalAmount() const { return withdrawalAmount; }
};

class InvalidAccountException : public BankException {
public:
    InvalidAccountException() : BankException("Invalid account number!") {}
};

class NegativeAmountException : public BankException {
public:
    NegativeAmountException() : BankException("Amount cannot be negative!") {}
};

class BankAccount {
private:
    string accountNumber;
    double balance;
public:
    BankAccount(string accNo, double bal) : accountNumber(accNo), balance(bal) {}

    void withdraw(double amount) {
        if (amount < 0) {
            throw NegativeAmountException();
        }
        if (accountNumber.empty()) {
            throw InvalidAccountException();
        }
        if (amount > balance) {
            throw InsufficientFundsException(balance, amount);
        }
        balance -= amount;
        cout << "Withdrawal successful! New balance: " << balance << endl;
    }

    void deposit(double amount) {
        if (amount < 0) {
            throw NegativeAmountException();
        }
        balance += amount;
        cout << "Deposit successful! New balance: " << balance << endl;
    }
};

int main() {
    BankAccount acc("ACC123", 5000);

    // Test different exceptions
    try {
        acc.deposit(-100);  // Should throw NegativeAmountException
    }
    catch (const NegativeAmountException& e) {
        cout << "Exception: " << e.what() << endl;
    }

    try {
        acc.withdraw(10000);  // Should throw InsufficientFundsException
    }
    catch (const InsufficientFundsException& e) {
        cout << "Exception: " << e.what() << endl;
        cout << "Available Balance: " << e.getBalance() << endl;
        cout << "Requested Amount: " << e.getWithdrawalAmount() << endl;
    }

    try {
        BankAccount invalidAcc("", 1000);
        invalidAcc.withdraw(500);  // Should throw InvalidAccountException
    }
    catch (const InvalidAccountException& e) {
        cout << "Exception: " << e.what() << endl;
    }

    cout << "\nProgram completed successfully!" << endl;
    return 0;
}
